// lib/db.js
const productsCache = {
  value: [],
  refreshedAt: null,
};

function createProducts() {
  return [
    { id: 1, name: 'Laptop', price: 999, inventory: 42, available: true },
    { id: 2, name: 'Phone', price: 699, inventory: 18, available: true },
    { id: 3, name: 'Tablet', price: 499, inventory: 0, available: false },
    { id: 4, name: 'Headphones', price: 199, inventory: 76, available: true },
    { id: 5, name: 'Watch', price: 299, inventory: 12, available: true },
  ];
}

export async function getAllProducts() {
  if (productsCache.value.length === 0) {
    await new Promise((resolve) => setTimeout(resolve, 100));
    productsCache.value = createProducts();
    productsCache.refreshedAt = new Date();
  }

  return productsCache.value;
}

export async function syncLatestCatalog() {
  await new Promise((resolve) => setTimeout(resolve, 50));
  productsCache.value = createProducts().map((product, index) => ({
    ...product,
    price: product.price + (index + 1) * 10,
    inventory: product.inventory + (index + 1) * 3,
    available: product.inventory + (index + 1) * 3 > 0,
  }));
  productsCache.refreshedAt = new Date();
}

export function getCatalogRefreshedAt() {
  return productsCache.refreshedAt;
}

export function getCatalogSnapshot() {
  return { products: productsCache.value, refreshedAt: productsCache.refreshedAt };
}


